mapper.select:
select a.id, a.title, a.summary, a.cover_image, a.category_id, c.name as category_name, a.author_id, u.nickname as author_name, a.status, a.is_top, a.view_count, a.publish_time, a.create_time from article a left join category c on a.category_id = c.id left join user u on a.author_id = u.id
and (a.title like concat('%', #{keyword}, '%') or a.summary like concat('%', #{keyword}, '%'))
and a.category_id = #{categoryId}
and a.status = #{status}
order by a.is_top desc, a.create_time desc, a.id desc limit #{offset}, #{pageSize}

select count(1)
from article a


        and (a.title like concat('%', #{keyword}, '%')
        or a.summary like concat('%', #{keyword}, '%'))


        and a.category_id = #{categoryId}


        and a.status = #{status}

mapper.update:
update article
set
    status = #{status},
    publish_time = #{publishTime}
where id = #{id}

mapper.select:
select distinct a.id, a.title, a.summary, a.cover_image, a.category_id, c.name as category_name, u.nickname as author_name, a.is_top, a.view_count, a.publish_time from article a left join category c on a.category_id = c.id left join user u on a.author_id = u.id left join article_tag at on a.id = at.article_id
a.status = 1
and (a.title like concat('%', #{keyword}, '%') or a.summary like concat('%', #{keyword}, '%'))
and a.category_id = #{categoryId}
and at.tag_id = #{tagId}
order by a.is_top desc, a.publish_time desc, a.id desc limit #{offset}, #{pageSize}

select count(distinct a.id) from article a left join article_tag at on a.id = at.article_id
a.status = 1
and (a.title like concat('%', #{keyword}, '%') or a.summary like concat('%', #{keyword}, '%'))
and a.category_id = #{categoryId}
and at.tag_id = #{tagId}

mapper.update:
update article
set view_count = view_count + 1
where id = #{id}

mapper.select:
select count(1)
from article
where status = #{status}
